<!doctype html>
<html lang="pl">
<head>
 <meta charset="utf-8">
 <meta name="viewport" content="width=device-width, initial-scale=1">
 <title>DRN-BMB7 - instrukcja API</title>
 <style>
 :root {
 --bg: #0f172a;
 --card: #111827;
 --text: #e5e7eb;
 --muted: #94a3b8;
 --line: #334155;
 --accent: #22d3ee;
 }
 * { box-sizing: border-box; }
 body {
 margin: 0;
 font-family: Arial, sans-serif;
 line-height: 1.55;
 background: linear-gradient(180deg, #020617 0%, #0f172a 100%);
 color: var(--text);
 }
 .container {
 max-width: 980px;
 margin: 0 auto;
 padding: 28px 16px 40px;
 }
 .card {
 background: rgba(17, 24, 39, 0.92);
 border: 1px solid var(--line);
 border-radius: 12px;
 padding: 18px;
 margin-bottom: 14px;
 }
 h1, h2, h3 { margin: 0 0 10px; }
 h1 { font-size: 30px; color: #67e8f9; }
 h2 {
 font-size: 21px;
 margin-top: 2px;
 border-bottom: 1px solid var(--line);
 padding-bottom: 6px;
 }
 h3 { font-size: 18px; margin-top: 16px; }
 p { margin: 0 0 10px; color: var(--text); }
 .muted { color: var(--muted); }
 ul { margin: 6px 0 8px 22px; }
 li { margin: 2px 0; }
 code {
 font-family: "Courier New", monospace;
 background: rgba(148, 163, 184, 0.2);
 border: 1px solid rgba(148, 163, 184, 0.35);
 border-radius: 5px;
 padding: 1px 6px;
 color: #e2e8f0;
 }
 pre {
 margin: 0;
 overflow-x: auto;
 padding: 12px;
 border-radius: 8px;
 background: #0b1220;
 border: 1px solid var(--line);
 color: #d1fae5;
 }
 table {
 width: 100%;
 border-collapse: collapse;
 margin-top: 10px;
 border: 1px solid var(--line);
 }
 th, td {
 text-align: left;
 vertical-align: top;
 border: 1px solid var(--line);
 padding: 9px 10px;
 }
